        "收集内容": "产品库存数量、异常库存预警"
      },
      "crm_customers": {
        "负责": "CRM客户动态",
        "工具": "crm_list_customers + crm_get_customer",
        "收集内容": "VIP客户情况、客户变动趋势"
      },
      "knowledge_base": {
        "负责": "知识库",
        "工具": "kb_search + kb_get_article",
        "收集内容": "过时文档标记、更新需求"
      },
      "scheduler_jobs": {
        "负责": "定时任务状态",
        "工具": "scheduler_list_jobs + scheduler_job_history",
        "收集内容": "调度任务健康状况、执行异常记录"
      }
    },
